import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import Navbar from './components/Navbar';
import Register from './components/Register';
import Login from './components/Login';
import VideoCard from './components/VideoCard';
import PlaylistCard from './components/PlaylistCard';
import VideoPlayer from './components/VideoPlayer';

const App = () => {
  return (
    <Router>
      <Navbar />
      <Routes>
        <Route path="/register" element={<Register />} />
        <Route path="/login" element={<Login />} />
        <Route path="/" element={<Home />} />
      </Routes>
    </Router>
  );
};

const Home = () => {
  const sampleVideo = {
    title: 'Sample Video',
    description: 'This is a sample video.',
    url: 'http://techslides.com/demos/sample-videos/small.mp4',
    thumbnail: 'http://via.placeholder.com/300x200'
  };

  const samplePlaylist = {
    name: 'Sample Playlist',
    description: 'This is a sample playlist.'
  };

  return (
    <div>
      <h1>Bem-vindo ao StreamingHub</h1>
      <VideoCard video={sampleVideo} />
      <PlaylistCard playlist={samplePlaylist} />
      <VideoPlayer video={sampleVideo} />
    </div>
  );
};

export default App;
